/**
 * Integration tests for the full notification pipeline.
 *
 * Tests the end-to-end flow: EventBus/CallbackRegistry triggers →
 * NotificationService dispatch → preferences check → adapter delivery →
 * history logging.
 *
 * All components are real (no mocks) — the adapters use no-op transports
 * but still validate recipients, render templates, and record deliveries.
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { NotificationHistoryService, resetLogIdCounter } from '../../src/services/notification-history.service.js';
import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { Database } from '../../src/utils/database.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../../src/events/event-types.js';
import type { NotificationAdapter } from '../../src/adapters/notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../../src/models/notification.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeUser(overrides: Partial<{ id: string; name: string; email: string }> = {}) {
  return {
    id: overrides.id ?? 'user-1',
    name: overrides.name ?? 'Alice',
    email: overrides.email ?? 'alice@example.com',
    role: 'member' as const,
    createdAt: new Date(),
    updatedAt: new Date(),
  };
}

function makeOrder(overrides: Partial<{ id: string; userId: string; status: string }> = {}) {
  return {
    id: overrides.id ?? 'order-1',
    userId: overrides.userId ?? 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
    total: 20,
    status: (overrides.status ?? 'pending') as 'pending',
    createdAt: new Date(),
    updatedAt: new Date(),
  };
}

// ---------------------------------------------------------------------------
// Test suite
// ---------------------------------------------------------------------------

describe('Notification Pipeline Integration', () => {
  let db: Database;
  let eventBus: EventBus;
  let emailAdapter: EmailAdapter;
  let smsAdapter: SmsAdapter;
  let webhookAdapter: WebhookAdapter;
  let preferencesRepo: PreferencesRepository;
  let preferencesService: PreferencesService;
  let logRepo: NotificationLogRepository;
  let historyService: NotificationHistoryService;
  let service: NotificationService;

  beforeEach(() => {
    // Reset global state
    resetNotificationIdCounter();
    resetLogIdCounter();
    resetPreferencesIdCounter();
    statusChangeCallbacks.clear();

    // Fresh database for each test
    db = new Database();

    // Adapters (all use no-op transports)
    emailAdapter = new EmailAdapter();
    smsAdapter = new SmsAdapter();
    webhookAdapter = new WebhookAdapter({ url: 'https://hooks.example.com/notify' });

    // Repositories
    preferencesRepo = new PreferencesRepository(db);
    logRepo = new NotificationLogRepository(db);

    // Services
    preferencesService = new PreferencesService(preferencesRepo);
    historyService = new NotificationHistoryService(logRepo);

    // EventBus + NotificationService with all adapters, preferences, and history
    eventBus = new EventBus();
    service = new NotificationService(
      eventBus,
      [emailAdapter, smsAdapter, webhookAdapter],
      preferencesService,
      historyService,
    );
  });

  // =========================================================================
  // Email notification delivery (full EventBus path)
  // =========================================================================

  describe('Email notification delivery', () => {
    it('should send email notification when order:created event is emitted', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Email adapter received the notification
      const sentEmails = emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]!.rendered.to).toBe('alice@example.com');
      expect(sentEmails[0]!.rendered.subject).toContain('Order Confirmation');
      expect(sentEmails[0]!.rendered.html).toContain('Order Confirmation');
      expect(sentEmails[0]!.rendered.text).toContain('Widget x2');

      // Service records the notification
      const records = service.getNotificationRecords();
      expect(records).toHaveLength(1);
      expect(records[0]!.payload.type).toBe('order_confirmation');
      expect(records[0]!.payload.channel).toBe('email');
      expect(records[0]!.result.success).toBe(true);
    });

    it('should send welcome email when user:created event is emitted', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: makeUser({ name: 'Bob', email: 'bob@example.com', id: 'user-2' }),
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const sentEmails = emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]!.rendered.to).toBe('bob@example.com');
      expect(sentEmails[0]!.rendered.subject).toBe('Welcome to TaskFlow Pro!');
      expect(sentEmails[0]!.rendered.html).toContain('Welcome to TaskFlow Pro!');
      expect(sentEmails[0]!.rendered.text).toContain('Bob');
    });

    it('should send account update email when user:updated event is emitted', async () => {
      const event: UserUpdatedEvent = {
        type: 'user:updated',
        user: makeUser(),
        changes: ['email', 'name'],
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const sentEmails = emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]!.rendered.subject).toBe('Account Updated');
      expect(sentEmails[0]!.rendered.text).toContain('Account Updated');

      const records = service.getNotificationRecords();
      expect(records[0]!.payload.type).toBe('account_updated');
      expect(records[0]!.payload.priority).toBe('low');
    });

    it('should send order status update via callback registry path', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: makeOrder({ status: 'confirmed' }),
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);
      await service.waitForPendingDispatches();

      // The recipient for status change is order.userId (not an email).
      // The email adapter will fail validation since "user-1" is not a valid email.
      const records = service.getNotificationRecords();
      expect(records).toHaveLength(1);
      expect(records[0]!.payload.type).toBe('order_status_update');
      expect(records[0]!.payload.subject).toContain('Order Update');
    });

    it('should send order status update via EventBus path', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: makeOrder({ status: 'shipped' }),
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const records = service.getNotificationRecords();
      expect(records).toHaveLength(1);
      expect(records[0]!.payload.type).toBe('order_status_update');
      expect(records[0]!.payload.body).toContain('confirmed');
      expect(records[0]!.payload.body).toContain('shipped');
    });
  });

  // =========================================================================
  // SMS notification delivery
  // =========================================================================

  describe('SMS notification delivery', () => {
    it('should send SMS notification through the dispatch pipeline', async () => {
      // The built-in handlers only dispatch to email channel.
      // To test SMS through the full pipeline (preferences → adapter → history),
      // we access the private dispatch method directly.
      await (service as any).dispatch({
        type: 'order_confirmation',
        channel: 'sms',
        recipient: '+15551234567',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed.',
        priority: 'normal',
        metadata: { orderId: 'order-1', userId: 'user-1' },
      });

      // SMS adapter received and sent the message
      const sentMessages = smsAdapter.getSentMessages();
      expect(sentMessages).toHaveLength(1);
      expect(sentMessages[0]!.message.to).toBe('+15551234567');
      expect(sentMessages[0]!.message.body).toContain('Order Confirmation');
      expect(sentMessages[0]!.message.body).toContain('Your order has been placed.');

      // Service records the notification
      const records = service.getNotificationRecords();
      expect(records).toHaveLength(1);
      expect(records[0]!.payload.channel).toBe('sms');
      expect(records[0]!.result.success).toBe(true);
      expect(records[0]!.result.channel).toBe('sms');
    });

    it('should fail SMS delivery for invalid phone number', async () => {
      await (service as any).dispatch({
        type: 'welcome',
        channel: 'sms',
        recipient: 'not-a-phone',
        subject: 'Welcome',
        body: 'Welcome to TaskFlow Pro!',
        priority: 'normal',
        metadata: { userId: 'user-1' },
      });

      // Adapter rejects invalid phone, but never throws (returns failure result)
      const sentMessages = smsAdapter.getSentMessages();
      expect(sentMessages).toHaveLength(0);

      const records = service.getNotificationRecords();
      expect(records).toHaveLength(1);
      expect(records[0]!.result.success).toBe(false);
      expect(records[0]!.result.error).toContain('Invalid phone number');
    });
  });

  // =========================================================================
  // Webhook notification delivery
  // =========================================================================

  describe('Webhook notification delivery', () => {
    it('should send webhook notification through the dispatch pipeline', async () => {
      await (service as any).dispatch({
        type: 'order_status_update',
        channel: 'webhook',
        recipient: 'https://hooks.example.com/notify',
        subject: 'Order Update: order-1',
        body: 'Status changed from pending to shipped.',
        priority: 'normal',
        metadata: { orderId: 'order-1', previousStatus: 'pending', newStatus: 'shipped' },
      });

      // Webhook adapter formatted and delivered the payload
      const delivered = webhookAdapter.getDeliveredPayloads();
      expect(delivered).toHaveLength(1);
      expect(delivered[0]!.webhookPayload.event).toBe('notification.order_status_update');
      expect(delivered[0]!.webhookPayload.notification.subject).toContain('Order Update');
      expect(delivered[0]!.webhookPayload.notification.recipient).toBe('https://hooks.example.com/notify');
      expect(delivered[0]!.webhookPayload.notification.metadata.orderId).toBe('order-1');

      // Service records the notification
      const records = service.getNotificationRecords();
      expect(records).toHaveLength(1);
      expect(records[0]!.payload.channel).toBe('webhook');
      expect(records[0]!.result.success).toBe(true);
    });

    it('should fail webhook delivery for invalid URL config', async () => {
      // Create a webhook adapter with an invalid URL
      const badWebhookAdapter = new WebhookAdapter({ url: 'not-a-url' });
      const freshEventBus = new EventBus();
      statusChangeCallbacks.clear();
      const freshService = new NotificationService(
        freshEventBus,
        [badWebhookAdapter],
        preferencesService,
        historyService,
      );

      await (freshService as any).dispatch({
        type: 'welcome',
        channel: 'webhook',
        recipient: 'test',
        subject: 'Test',
        body: 'Test body',
        priority: 'normal',
        metadata: { userId: 'user-1' },
      });

      const records = freshService.getNotificationRecords();
      expect(records).toHaveLength(1);
      expect(records[0]!.result.success).toBe(false);
      expect(records[0]!.result.error).toContain('Invalid webhook URL');
    });
  });

  // =========================================================================
  // Notification history logging
  // =========================================================================

  describe('Notification history', () => {
    it('should log successful email delivery in history', async () => {
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      expect(historyService.count()).toBe(1);

      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.channel).toBe('email');
      expect(logs[0]!.type).toBe('order_confirmation');
      expect(logs[0]!.status).toBe('delivered');
      expect(logs[0]!.error).toBeUndefined();
      expect(logs[0]!.subject).toContain('Order Confirmation');
      expect(logs[0]!.metadata.orderId).toBe('order-1');
    });

    it('should log failed delivery in history', async () => {
      // Dispatch to a channel with no adapter registered
      const freshEventBus = new EventBus();
      statusChangeCallbacks.clear();
      const freshService = new NotificationService(
        freshEventBus,
        [], // no adapters
        preferencesService,
        historyService,
      );

      await freshEventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      const logs = historyService.query({ status: 'failed' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('failed');
      expect(logs[0]!.error).toContain('No adapter for channel');
    });

    it('should log SMS delivery in history', async () => {
      await (service as any).dispatch({
        type: 'order_confirmation',
        channel: 'sms',
        recipient: '+15559876543',
        subject: 'Order Confirmation',
        body: 'Your order was placed.',
        priority: 'normal',
        metadata: { orderId: 'order-2', userId: 'user-2' },
      });

      const logs = historyService.query({ channel: 'sms' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.recipient).toBe('+15559876543');
      expect(logs[0]!.channel).toBe('sms');
      expect(logs[0]!.status).toBe('delivered');
    });

    it('should log webhook delivery in history', async () => {
      await (service as any).dispatch({
        type: 'welcome',
        channel: 'webhook',
        recipient: 'https://hooks.example.com/notify',
        subject: 'Welcome',
        body: 'Welcome to TaskFlow Pro!',
        priority: 'normal',
        metadata: { userId: 'user-3' },
      });

      const logs = historyService.query({ channel: 'webhook' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.channel).toBe('webhook');
      expect(logs[0]!.status).toBe('delivered');
    });

    it('should query history by type across channels', async () => {
      // Send an email via EventBus
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      // Send an SMS for the same notification type
      await (service as any).dispatch({
        type: 'order_confirmation',
        channel: 'sms',
        recipient: '+15551112222',
        subject: 'Order Confirmation',
        body: 'Your order was placed.',
        priority: 'normal',
        metadata: { orderId: 'order-1', userId: 'user-1' },
      });

      const logs = historyService.getByType('order_confirmation');
      expect(logs).toHaveLength(2);
      expect(logs.map((l) => l.channel).sort()).toEqual(['email', 'sms']);
    });
  });

  // =========================================================================
  // User preferences enforcement
  // =========================================================================

  describe('User preferences', () => {
    it('should send email when user has email preferences enabled (default)', async () => {
      // Default preferences: email enabled. No explicit setup needed.
      await eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      const sentEmails = emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);

      const logs = historyService.query({ status: 'delivered' });
      expect(logs).toHaveLength(1);
    });

    it('should suppress email when user has email globally disabled', async () => {
      // Disable email for user-1
      preferencesService.updateEmailPreferences('user-1', { enabled: false });

      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      // No email sent
      const sentEmails = emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(0);

      // No notification records (suppressed notifications are not recorded)
      expect(service.getNotificationCount()).toBe(0);

      // No history logged (suppressed before dispatch)
      expect(historyService.count()).toBe(0);
    });

    it('should suppress email when specific category is disabled', async () => {
      // Disable order_confirmation category for email
      preferencesService.updateEmailPreferences('user-1', {
        categories: { order_confirmation: false },
      });

      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      // Suppressed
      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      expect(service.getNotificationCount()).toBe(0);
    });

    it('should still send allowed categories when one category is disabled', async () => {
      // Disable order_confirmation but keep welcome enabled
      preferencesService.updateEmailPreferences('user-1', {
        categories: { order_confirmation: false },
      });

      // This should be suppressed (order_confirmation)
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      // This should go through (welcome)
      await eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(emailAdapter.getSentEmails()[0]!.rendered.subject).toBe('Welcome to TaskFlow Pro!');
