      const trackingAdapter: NotificationAdapter = {
        channel: 'email' as const,
        async send(payload: NotificationPayload): Promise<NotificationResult> {
          callCount++;
          // First call is slower than second
          const delay = callCount === 1 ? 40 : 5;
          await new Promise((resolve) => setTimeout(resolve, delay));
          deliveryOrder.push(payload.type);
          return { success: true, channel: 'email', deliveredAt: new Date() };
        },
      };

      const freshEventBus = new EventBus();
      statusChangeCallbacks.clear();
